import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"System Workers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/system-workers.md","filePath":"guide/admin/system-workers.md","lastUpdated":1778912818000}'),s={name:"guide/admin/system-workers.md"};function n(i,t,l,d,u,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="system-workers" tabindex="-1">System Workers <a class="header-anchor" href="#system-workers" aria-label="Permalink to &quot;System Workers&quot;">​</a></h1><p>The <strong>System → Workers</strong> page monitors background workers that the Console runs on a schedule — things like the discrepancy audit, the changelog publisher, billing computations, and so on. It is read-only.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>A single table with an auto-refresh notice and a manual <strong>Refresh</strong> button at the top. The page reloads worker status every 30 seconds automatically.</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Expand</strong></td><td>Icon shown if details are available.</td></tr><tr><td><strong>Worker name</strong></td><td>The internal worker identifier.</td></tr><tr><td><strong>Interval</strong></td><td>Execution schedule (e.g. &quot;every 5 minutes&quot;).</td></tr><tr><td><strong>Status</strong></td><td>Success / Failed / Never Run badge.</td></tr><tr><td><strong>Last Run</strong></td><td>Relative timestamp.</td></tr><tr><td><strong>Duration</strong></td><td>Milliseconds or seconds.</td></tr><tr><td><strong>Details / Error preview</strong></td><td>One-line teaser — either error message or run metadata.</td></tr></tbody></table><h2 id="expanded-panel" tabindex="-1">Expanded panel <a class="header-anchor" href="#expanded-panel" aria-label="Permalink to &quot;Expanded panel&quot;">​</a></h2><p>Click a row (or the expand icon) to slide open a detail panel:</p><ul><li><strong>Failed runs</strong> show the full error message in monospace red text.</li><li><strong>Successful runs</strong> show a 4-column grid of run metadata (processed counts, tenants synced, anything the worker reported).</li><li>Common details: started time, duration, run ID, interval.</li></ul><h2 id="what-you-typically-use-this-page-for" tabindex="-1">What you typically use this page for <a class="header-anchor" href="#what-you-typically-use-this-page-for" aria-label="Permalink to &quot;What you typically use this page for&quot;">​</a></h2><ul><li>Spotting workers that have not run in their expected window.</li><li>Reading the error from the most recent failure of a worker.</li><li>Confirming a worker is healthy after a deploy.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The page shows only the <strong>most recent run</strong> per worker, not the full history. For historical runs you would need to look at backend logs.</li><li>&quot;Never Run&quot; usually means the worker was added but has not reached its first scheduled tick. After one interval it should flip to Success or Failed.</li><li>This is an operator page. Customers do not see it.</li></ul>',13)])])}const p=e(s,[["render",n]]);export{m as __pageData,p as default};
